import React, { useState } from 'react';

export default function HoverEffect({ items }) {
  const [hoveredIndex, setHoveredIndex] = useState(null);

  return (
    <div className="grid grid-cols-1 md:grid-cols-3 py-10 max-w-5xl mx-auto">
      {items.map((item, idx) => (
        <div
          key={idx}
          className="relative group block p-2 h-full w-full"
          onMouseEnter={() => setHoveredIndex(idx)}
          onMouseLeave={() => setHoveredIndex(null)}
        >
          {/* Sliding Backdrop Highlighting Block */}
          <div
            className={`absolute inset-0 h-full w-full bg-neutral-200/80 dark:bg-slate-800/[0.8] block rounded-3xl transition-all duration-300 -z-10 ${
              hoveredIndex === idx ? 'scale-100 opacity-100' : 'scale-95 opacity-0'
            }`}
          />

          {/* Card Body */}
          <div className="rounded-2xl h-full w-full p-4 overflow-hidden bg-white border border-gray-200 group-hover:border-slate-300 dark:bg-black dark:border-slate-800 relative z-20 transition duration-200">
            <div className="relative z-50">
              <h4 className="text-zinc-800 dark:text-zinc-100 font-bold tracking-wide mt-4">
                {item.title}
              </h4>
              <p className="mt-4 text-zinc-500 dark:text-zinc-400 tracking-wide leading-relaxed text-sm">
                {item.description}
              </p>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}
